// historyTimeAgo returns a human-readable relative time string.
func historyTimeAgo(t time.Time) string {
	dur := time.Since(t)
	switch {
	case dur < time.Minute:
		return "just now"
	case dur < time.Hour:
		m := int(dur.Minutes())
		if m == 1 {
			return "1 minute ago"
		}
		return strconv.Itoa(m) + " minutes ago"
	case dur < 24*time.Hour:
		h := int(dur.Hours())
		if h == 1 {
			return "1 hour ago"
		}
		return strconv.Itoa(h) + " hours ago"
	case dur < 7*24*time.Hour:
		d := int(dur.Hours() / 24)
		if d == 1 {
			return "1 day ago"
		}
		return strconv.Itoa(d) + " days ago"
	default:
		return t.Format("Jan 2, 2006")
	}
}

// historySourceLabel converts a source string to a human-readable label.
func historySourceLabel(source string) string {
	switch {
	case source == "manual":
		return "Manual"
	case source == "scan":
		return "Scan"
	case source == "import":
		return "Import"
	case strings.HasPrefix(source, "provider:"):
		name := strings.TrimPrefix(source, "provider:")
		if name == "" {
			return "Provider"
		}
		return "Provider: " + name
	case strings.HasPrefix(source, "rule:"):
		ruleID := strings.TrimPrefix(source, "rule:")
		if ruleID == "" {
			return "Rule"
		}
		return "Rule: " + ruleID
	default:
		return source
	}
}

// historyFieldLabel converts a database field name to a human-readable label.
func historyFieldLabel(field string) string {
	labels := map[string]string{
		"biography":      "Biography",
		"genres":         "Genres",
		"styles":         "Styles",
		"moods":          "Moods",
		"formed":         "Formed",
		"born":           "Born",
		"disbanded":      "Disbanded",
		"died":           "Died",
		"years_active":   "Years Active",
		"type":           "Type",
		"gender":         "Gender",
		"sort_name":      "Sort Name",
		"name":           "Name",
		"thumb":          "Thumbnail",
		"fanart":         "Fanart",
		"logo":           "Logo",
		"banner":         "Banner",
		"musicbrainz_id": "MusicBrainz ID",
		"audiodb_id":     "AudioDB ID",
		"discogs_id":     "Discogs ID",
		"wikidata_id":    "Wikidata ID",
		"deezer_id":      "Deezer ID",
		"spotify_id":     "Spotify ID",
		"members":        "Band Members",
	}
	if label, ok := labels[field]; ok {
		return label
	}
	// Convert snake_case to Title Case as fallback.
	parts := strings.Split(field, "_")
	for i, p := range parts {
		if len(p) > 0 {
			parts[i] = strings.ToUpper(p[:1]) + p[1:]
		}
	}
	return strings.Join(parts, " ")
}

// historyTruncate trims a string to at most maxLen visible characters, adding
// an ellipsis if truncation occurs. Uses rune-based length to handle multi-byte
// Unicode correctly.
func historyTruncate(s string, maxLen int) string {
	// Normalize newlines for display.
	s = strings.ReplaceAll(s, "\n", " ")
	s = strings.ReplaceAll(s, "\r", "")
	runes := []rune(s)
	if len(runes) <= maxLen {
		return s
	}
	return string(runes[:maxLen]) + "..."
}

